*event_2
;[exp] onObjectTrigger
*event_3
;[exp] onObjectTrigger

@barrel
@damage v=&'game.curTarget.addParam("life", 200)'
@notice text=&'"<p>" + game.curTarget.displayName + "<w> had HP restored!"'

[eventoff]
;-------------------------------------------------------------------------------
*event_4
;[exp] onObjectTrigger

@barrel
@damage v=&'game.curTarget.addParam("maxLife", 20)'
@notice text=&'"<p>" + game.curTarget.displayName + "<w> had max HP permanently increased by 20!"'

[eventoff]
